import { existsSync, mkdirSync, readFileSync, rmSync, unlinkSync, writeFileSync } from "node:fs";
import { homedir } from "node:os";
import { join, normalize } from "node:path";
import { createInterface } from "node:readline/promises";
import { emitKeypressEvents } from "node:readline";
import { spawnSync, type SpawnSyncOptions } from "node:child_process";

type Platform = "macos" | "linux" | "windows" | "wsl";
type ProviderKey = "bitbucket" | "github" | "gitlab" | "azure";
type CommandName = "setup" | "test" | "list" | "remove" | "copy" | "config" | "agent" | "help" | "version";

type SetupOptions = {
  provider?: ProviderKey;
  email?: string;
  key?: string;
  host?: string;
  force: boolean;
  noGitConfig: boolean;
  noBrowser: boolean;
  noClipboard: boolean;
};

type ParsedCommand =
  | { name: "help" }
  | { name: "version" }
  | { name: "setup"; options: SetupOptions }
  | { name: "test"; host: string }
  | { name: "list" }
  | { name: "remove"; key: string }
  | { name: "copy"; key: string }
  | { name: "config"; host?: string }
  | { name: "agent"; action: "list" | "add" | "remove"; key?: string };

type GitContext = {
  email?: string;
  username?: string;
  provider?: ProviderKey;
  remoteUrl?: string;
};

type ConfigSegment =
  | { kind: "text"; lines: string[] }
  | { kind: "host"; host: string; lines: string[] };

type CommandResult = {
  status: number;
  stdout: string;
  stderr: string;
};

const PROVIDERS: Record<
  ProviderKey,
  {
    label: string;
    hostname: string;
    settingsUrl: string;
    keyType: "ed25519" | "rsa";
  }
> = {
  bitbucket: {
    label: "Bitbucket",
    hostname: "bitbucket.org",
    settingsUrl: "https://bitbucket.org/account/settings/ssh-keys/",
    keyType: "ed25519",
  },
  github: {
    label: "GitHub",
    hostname: "github.com",
    settingsUrl: "https://github.com/settings/keys",
    keyType: "ed25519",
  },
  gitlab: {
    label: "GitLab",
    hostname: "gitlab.com",
    settingsUrl: "https://gitlab.com/-/profile/keys",
    keyType: "ed25519",
  },
  azure: {
    label: "Azure DevOps",
    hostname: "ssh.dev.azure.com",
    settingsUrl: "https://dev.azure.com/_usersSettings/keys",
    keyType: "rsa",
  },
};

const PACKAGE_VERSION = readPackageVersion();
const SSH_DIR = join(homedir(), ".ssh");
const SSH_CONFIG_PATH = join(SSH_DIR, "config");

function readPackageVersion(): string {
  try {
    const packageJson = JSON.parse(readFileSync(join(__dirname, "..", "package.json"), "utf8")) as {
      version?: string;
    };
    return packageJson.version || "0.0.0";
  } catch {
    return "0.0.0";
  }
}

